-- PostgreSQL migration-ready seed for Uzbek natural-style names
-- Note: 40,000 rows total = 20,000 male + 20,000 female.
-- The earliest rows are common/curated names; later rows are natural Uzbek-style compound names built from widely used naming elements.
BEGIN;
CREATE TABLE IF NOT EXISTS uzbek_names (
    id BIGSERIAL PRIMARY KEY,
    name VARCHAR(128) NOT NULL,
    gender VARCHAR(10) NOT NULL CHECK (gender IN ('male', 'female')),
    meaning_uz TEXT NOT NULL,
    source_type VARCHAR(20) NOT NULL DEFAULT 'curated',
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE UNIQUE INDEX IF NOT EXISTS ux_uzbek_names_lower_gender ON uzbek_names (LOWER(name), gender);
ON CONFLICT (LOWER(name), gender) DO NOTHING;
COMMIT;